      "point": "Consistent Performance Improvement",
      "evidence": "TSP consistently outperforms pure MLM and existing inter-sentence baselines (NSP, SOP, SSO) across Small, Base, and Large model scales on SuperGLUE."
    },
    {
      "point": "Beneficial on Reasoning and QA Tasks",
      "evidence": "TSP performed well on reasoning (CB, RTE, COPA) and question-answering (MultiRC, BoolQ) tasks."
    },
    {
      "point": "Ablation Study Support",
      "evidence": "Ablation study showed both hierarchical and ordering relationships in TSP were found to be beneficial, and both outperformed MLM alone."
    },
    {
      "point": "Extensibility to Other Architectures",
      "evidence": "TSP also improved performance when combined with ELECTRA (a different word-level pretraining method) at the Small scale."
    },
    {
      "point": "Novel Pretraining Objective",
      "evidence": "Introduced TSP as a novel inter-sentence pretraining task that leverages text structure information to provide more valuable learning signals."
    }
  ],
